&lt;li&gt;&lt;a href=&#34;https://github.com/YSGStudyHards/DotNetGuide/blob/main/docs/DotNet/DotNetProjectPicks.md#%E5%85%B6%E4%BB%96%E7%AC%AC%E4%B8%89%E6%96%B9sdk%E7%B1%BB%E5%BA%93&#34;&gt;其他第三方 SDK &amp;amp; 类库&lt;/a&gt;&lt;/li&gt;
