&lt;li&gt;&lt;a href=&#34;https://github.com/YSGStudyHards/DotNetGuide/blob/main/docs/DotNet/DotNetProjectPicks.md#%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84%E4%B8%8E%E7%AE%97%E6%B3%95&#34;&gt;数据结构与算法&lt;/a&gt;&lt;/li&gt;
