&lt;td style=&#34;text-align:center&#34;&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1RdWFydHotMmwyancxb25xenZ1MWQuTmV0&#34;&gt;可嵌入的 Quartz.Net&lt;/span&gt; Web 控制台。&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;a href=&#34;https://github.com/mausch/QuartzNetWebConsole&#34;&gt;https://github.com/mausch/QuartzNetWebConsole&lt;/a&gt;&lt;/td&gt;
