&lt;td style=&#34;text-align:center&#34;&gt;&lt;a href=&#34;https://github.com/ViewFaceCore/ViewFaceCore&#34;&gt;https://github.com/ViewFaceCore/ViewFaceCore&lt;/a&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
